	function emitQueryTeamProgress(onUpdate: any, details: QueryTeamDetails) {
		try {
			onUpdate?.({
				content: [{
					type: "text",
					text: `team ${details.team}: ${details.completed}/${details.requestedQueries.length} completed, ${details.failed} failed`,
				}],
				details,
			});
		} catch {
			// noop
